import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XssFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Proper encoding to prevent XSS
        String sanitizedInput = sanitizeInput(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");
        out.println(sanitizedInput); // Output sanitized user input
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper encoding/escaping based on your application's needs
        // For example, using OWASP Java Encoder library for HTML encoding:
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

